const ONE =
  'M110 24.5C111.381 24.5003 112.5 25.6194 112.5 27V33C112.5 34.3806 111.381 35.4997 110 35.5C108.62 35.5 107.5 34.3807 107.5 33V27C107.5 25.6193 108.62 24.5 110 24.5Z';
const ZERO =
  'M20.0005 26C22.2094 26.0003 24.0005 27.791 24.0005 30C24.0005 32.209 22.2094 33.9997 20.0005 34C17.7913 34 16.0005 32.2091 16.0005 30C16.0005 27.7909 17.7913 26 20.0005 26Z';

export default function Splash() {
  const navigate = useNavigate();
  const [nonce, setNonce] = useState(0);
  const [done, setDone] = useState(false);

  useEffect(() => {
    const t = window.setTimeout(() => setDone(true), 3100);
    return () => window.clearTimeout(t);
  }, [nonce]);

  const replay = () => {
    setDone(false);
    setNonce((n) => n + 1);
  };

  return (
    <div className="min-h-screen bg-paper flex flex-col items-center justify-center px-6">
      <div key={nonce} className="flex flex-col items-center">
        <svg
          viewBox="0 0 125 125"
          className="w-[240px] sm:w-[300px] h-auto text-primary"
          fill="currentColor"
          xmlns="http://www.w3.org/2000/svg"
          aria-label="Weave"
        >
          <defs>
            {/*
              W를 "써내려가듯" 그리기 위한 mask.
              - 검은 배경 위에, W의 중심선을 따라가는 굵은 흰 stroke를
                stroke-dashoffset 으로 풀어내면 그 부분만 마스킹이 풀려
                채워진 W body 가 한 획씩 드러남.
              - pathLength=1 로 dash 를 정규화해 타이밍이 균일.
            */}
            <mask id="splash-w-mask" maskUnits="userSpaceOnUse" x="0" y="0" width="125" height="125">
              <rect x="0" y="0" width="125" height="125" fill="black" />
              <path
                className="splash-w-draw"
                d="M 19.5 51 C 22 75, 38 102, 50 102 C 60 99, 62 75, 65 56 C 68 75, 70 99, 80 102 C 92 102, 108 75, 110.5 51"
                stroke="white"
                strokeWidth="32"
                strokeLinecap="round"
                strokeLinejoin="round"
                fill="none"
                pathLength="1"
              />
            </mask>
          </defs>

          {/* 0 — 좌측 상단 작은 원 */}
          <path className="splash-zero" d={ZERO} />

          {/* W — mask 가 stroke 를 따라 풀리며 한 획으로 드러남.
              .splash-w-group 으로 draw 시작 전까지 그룹을 완전히 숨겨서
              dash 경계의 round-cap 잔상이 우측에 비치는 현상 차단 */}
          <g className="splash-w-group" mask="url(#splash-w-mask)">
            <path d={WW_LEFT} />
            <path d={WW_RIGHT} />
          </g>

          {/* 1 — 우측 상단 짧은 선 */}
          <path className="splash-one" d={ONE} />
        </svg>

        <div className="splash-label mt-6 text-center">
          <div className="text-[28px] font-bold tracking-tighter text-primary">
            Weave
          </div>
          <div className="text-[13px] text-muted mt-1">
            시작에 헤매는 시간을 없애다
          </div>
        </div>
      </div>

      {/* 컨트롤 — 애니메이션 종료 후 노출 */}
      <div
        className={`mt-10 flex items-center gap-3 transition-opacity duration-500 ${
          done ? 'opacity-100' : 'opacity-0 pointer-events-none'
        }`}
      >
        <button
          onClick={replay}
          className="flex items-center gap-1.5 text-[12px] font-bold text-muted hover:text-primary px-3 py-2 rounded-md border border-border bg-surface transition-colors"
        >
          <RotateCcw size={13} />
          다시 보기
        </button>
        <button
          onClick={() => navigate('/prototype/landing')}
          className="flex items-center gap-1.5 text-[12px] font-bold text-paper bg-primary px-4 py-2 rounded-md hover:opacity-90 transition-opacity"
        >
          시작하기
          <ArrowRight size={13} />
        </button>
      </div>

      <a
        href="/prototype"
        className="fixed top-4 left-4 text-[12px] text-muted hover:text-primary transition-colors"
      >
        ← 프로토타입 메뉴
      </a>
    </div>
  );
}
